mapper.select:
SELECT tdt.*
FROM esg.tb_contractor_sh_checklist_detail tdt
WHERE tdt.eval_type_id = #{searchText}
    AND comp_id = #{compId}
order by tdt.use_yn DESC, tdt.ord_seq ASC

SELECT tdt.*
FROM esg.tb_contractor_assmt_report_master tdt
WHERE tdt.write_year = #{writeYear}
    and tdt.doc_type = #{docType}
    and tdt.doc_no = #{docNo}
order by tdt.use_yn DESC, tdt.ord_seq ASC

SELECT tdt.*
FROM esg.tb_contractor_assmt_report_detail tdt
WHERE tdt.write_year = #{writeYear}
    AND tdt.doc_type = #{docType}
    AND tdt.doc_no = #{docNo}
    AND tdt.eval_type_id = #{evalTypeId}
order by tdt.use_yn DESC, tdt.ord_seq ASC

mapper.update:
UPDATE esg.tb_contractor_sh_checklist SET
    eval_type_nm = #{evalTypeNm},
    use_yn = #{useYn},
    ord_seq = #{ordSeq},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
    AND eval_type_id= #{evalTypeId};

UPDATE esg.tb_contractor_sh_checklist SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE eval_type_id = #{evalTypeId}
  AND comp_id = #{compId}

UPDATE esg.tb_contractor_sh_checklist_detail SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE eval_type_id = #{evalTypeId}
  AND comp_id = #{compId}

UPDATE esg.tb_contractor_sh_checklist_detail SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE eval_type_id = #{evalTypeId}
  AND eval_detail_id = #{evalDetailId}
  AND comp_id = #{compId}

UPDATE esg.tb_contractor_assmt_report SET
    use_yn='N'
    WHERE write_year = #{writeYear}
    and doc_type = #{docType}
    and doc_no = #{docNo}

