mapper.update:
UPDATE esg.tb_contractor_assmt_report_master SET
    eval_type_nm = #{evalTypeNm},
    use_yn = #{useYn},
    ord_seq = #{ordSeq},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
    AND doc_type = #{docType}
    AND doc_no = #{docNo}
    AND eval_type_id= #{evalTypeId};

UPDATE esg.tb_contractor_assmt_report_detail SET
    eval_detail_nm = #{evalDetailNm},
    weight=#{weight},
    use_yn = #{useYn},
    ord_seq = #{ordSeq},
    div_a=#{divA},
    div_b=#{divB},
    div_c=#{divC},
    div_d=#{divD},
    div_e=#{divE},
    point=#{point},
    updated_at = now(),
    updated_by = #{updatedBy}
    WHERE write_year = #{writeYear}
      AND doc_type = #{docType}
      AND doc_no = #{docNo}
      AND eval_type_id = #{evalTypeId}
      AND eval_detail_id = #{evalDetailId}

mapper.select:
   SELECT car.*,tpci.part_comp_nm, thi.hr_nm as assmt_manager_hr_nm
     FROM esg.tb_contractor_assmt_report car
LEFT JOIN esg.tb_partner_comp_info tpci
       ON car.part_comp_id = tpci.part_comp_id
LEFT JOIN esg.tb_hr_info thi
       ON car.assmt_manager_hr_id = thi.hr_id
    WHERE write_year = #{writeYear}
      AND doc_type = #{docType}
      AND tpci.part_comp_id = #{partCompId}
      AND car.doc_no = #{docNo}
 ORDER BY car.use_yn desc, car.assmt_dt desc
